using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Keep old name for backward compatibility with existing documents.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change: id no longer contains discriminator (was "Blog|1", now "1").
            // Preserve old composite id format for existing documents.
            b.HasDiscriminatorInJsonId();

            // Breaking change: key property now maps directly to JSON "id",
            // removing the separate stored property. Preserve old shadow-id behavior
            // so existing documents that store "Id" separately keep working.
            b.HasShadowId();
        });

        // Breaking change: HasIndex now throws for Cosmos (was silently ignored).
        // Removed — Cosmos indexes all properties by default.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

